  blocks.push({ type:'input', block_id:'f_sched', element:{ type:'plain_text_input', action_id:'v', initial_value: d.sched||'' }, label:{ type:'plain_text', text:'일정' }});
  blocks.push({ type:'input', block_id:'f_link', optional:true, element:{ type:'plain_text_input', action_id:'v', initial_value: d.link||'', placeholder:{ type:'plain_text', text:'줌링크를 입력해주세요' }}, label:{ type:'plain_text', text:'줌링크 (옵션)' }});
}
// ④ 당일 리마인드 — 공유회명+일정
